INSERT INTO [events] ([id], [title], [description], [event_date], [location], [image_url], [is_active], [created_at]) VALUES (1, 'Annual Parents Orientation & High Tea', 'An interactive session for parents to meet class teachers, understand the curriculum structure, and discuss milestones.', '2026-07-21 13:27:41.010', 'School Main Auditorium', '/assets/images/hero_kids_learning.jpg', 1, '2026-07-06 07:57:41.010');
INSERT INTO [events] ([id], [title], [description], [event_date], [location], [image_url], [is_active], [created_at]) VALUES (2, 'Monsoon Splash Carnival 2026', 'A fun-filled event with water games, splash pools, rain dance, and delicious snack stalls for children and parents.', '2026-08-05 13:27:41.010', 'School Open Turf Ground', '/assets/images/gallery_play.jpg', 1, '2026-07-06 07:57:41.010');
INSERT INTO [faqs] ([id], [question], [answer], [category], [is_active], [sort_order]) VALUES (1, 'What is the student-to-teacher ratio?', 'We maintain an optimal ratio of 10:1 for Toddlers and 12:1 for Kindergarten, each assisted by a qualified helper.', 'Admissions', 1, 1);
INSERT INTO [faqs] ([id], [question], [answer], [category], [is_active], [sort_order]) VALUES (2, 'Do you offer school transportation?', 'Yes, we provide safe, air-conditioned school buses with CCTV cameras, GPS tracking, and female bus attendants.', 'Facilities', 1, 2);
INSERT INTO [faqs] ([id], [question], [answer], [category], [is_active], [sort_order]) VALUES (3, 'How do you handle medical emergencies?', 'We have an in-house nurse, a fully stocked medical room, and a tied-up emergency response ambulance with nearby pediatric hospitals.', 'Safety', 1, 3);
INSERT INTO [faqs] ([id], [question], [answer], [category], [is_active], [sort_order]) VALUES (4, 'Is admissions open mid-term?', 'Yes, admissions for Toddlers and Daycare are open throughout the year, subject to seat availability.', 'Admissions', 1, 4);
