INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (1, 'home', 'hero', 'Igniting the Joy of Learning', 'Best Preschool Experience for your Little Ones', 'We offer a child-centered approach that develops key cognitive, motor, social, and emotional skills.', '[{"title": "Where Learning Meets Robotics & Play", "subtitle": "Meet your robot helper friends and start an adventure in early learning!", "image": "/assets/images/hero_robot_learning.png", "cta_text": "Apply Now", "cta_link": "/admissions"}, {"title": "Innovate, Build, and Grow!", "subtitle": "Building future-ready minds with creative coding, tiny robots, and endless imagination!", "image": "/assets/images/robot_creative_play.png", "cta_text": "Explore Curriculum", "cta_link": "/curriculum"}, {"title": "Innovate, Build, and Grow!", "subtitle": "Building future-ready minds with creative coding, tiny robots, and endless imagination!", "image": "/assets/images/robot_creative_play.png", "cta_text": "Place your Finger", "cta_link": "/"}]', '/assets/images/hero_kids_learning.jpg', 1, 1);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (2, 'home', 'about', 'Where Curious Kids & Friendly Robots Grow Together!', 'Our Playful Mission', 'Established with a vision to revolutionize early childhood education, Vidyankuram Club provides a nurturing environment where children are encouraged to ask questions, explore their surroundings, and discover their unique talents.', '[{"title": "Robo-Buddies", "desc": "Learn coding and problem solving alongside our cute, interactive classroom robot friends."}, {"title": "Mindset Builders", "desc": "Instilling a growth mindset where every child learns to design, test, and improve continuously."}, {"title": "Creative Coding", "desc": "Visual drag-and-drop games that turn complex logic into a fun, colorful playground."}, {"title": "Positive Playgrounds", "desc": "Encouraging social skills and empathy through collaborative building and engineering play."}]', '/assets/images/robot_science_experiment.png', 1, 2);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (3, 'home', 'programs', 'Choose Your Learning Adventure', 'Class Missions', 'Our curriculum is carefully structured across multiple age groups to ensure optimal growth and happy school memories.', NULL, NULL, 1, 3);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (4, 'home', 'gallery', 'Glimpses of Vidyankuram Club', 'Take a visual tour of our vibrant classrooms and active play areas', 'A peak into the daily activities, school celebrations, and learning projects done by our little achievers.', NULL, NULL, 1, 4);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (5, 'home', 'testimonials', 'What Our Proud Space Cadet Parents Say', 'Success Stories', 'Nothing speaks louder than the trust and testimonials of our loving parents.', NULL, NULL, 1, 5);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (6, 'home', 'events', 'Upcoming School Events', 'Stay updated with our latest learning and social activities', 'Join us in celebrating child milestones, open house exhibitions, and seasonal carnivals.', NULL, NULL, 1, 6);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (7, 'home', 'blogs', 'Educational Insights & Blogs', 'Parenting tips, early learning advice, and school highlights', 'Read articles written by our expert child educators to support your child''s growth path at home.', NULL, NULL, 1, 7);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (8, 'home', 'contact', 'Get in Touch', 'Have queries? We are here to help you register or answer questions', 'Fill the form to request a campus tour, download brochures, or book a free trial class.', NULL, NULL, 1, 8);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (9, 'curriculum', 'curriculum_info', 'Our Programmes & Curriculum', 'Innovation in Curriculum for Pre-school', 'A preschool has two programs - Playgroup and Nursery. The best age to get admission for playgroup is 2 years. For Nursery, the best age to start is 3 years. Vidyankuram Kids International Preschool will set a strong foundation for your child to join Junior KG at the age of 4 and senior KG at the age of 5. Vidyankuram Kids curriculum is designed to offer each child an engaging and developmentally fulfilling experience with Fluidic Learning Methodology.', '["Playgroup Program (Toddler transition, sensory exploration, and basic fine-motor wiggles).", "Nursery Program (Introduction to phonics, pre-writing skills, social collaboration, and blocks).", "Junior KG Program (Development of language confidence, pre-math logic, and creative expressions).", "Senior KG Program (Advanced reading, complex counting, logical reasoning, and social preparedness)."]', '/assets/images/curriculum_learning.png', 1, 1);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (10, 'why_us', 'why_us_info', 'Why Vidyankuram Kids?', 'learner centric & committed to child growth', 'Vidyankuram Kids has always been ‘learner centric’ and open to change which has reflected in our approach towards preschool, playschool, kindergarten, and nursery learning over the last 30 years. Our new age iCan Learning System has been developed to prepare our children to live in this thriving and accelerated world. We are committed to supporting your child''s growth and happiness as they go through life''s earliest developmental milestones.', '["Imparting Quality Education for over 30+ years.", "Excellent Teacher Student Ratio of 1:6.", "Innovative Curriculum & Pedagogy built for futuristic kids.", "The New Age iCan Learning System (agile and fluid methodology).", "Personalized Learning through structured plays and custom tools.", "Extended Learning at home using our in-house App.", "Highly Trained, certified, and experienced Early Childhood educators."]', '/assets/images/why_Vidyankuram_kids.png', 1, 1);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (11, 'preschool_program', 'preschool_hero', 'Preschooling Programme', 'The iCan Learning System', 'Nurturing young minds through experiential play and a future-ready curriculum designed for holistic early childhood development.', NULL, '/assets/images/program_preschool.jpg', 1, 1);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (12, 'preschool_program', 'playgroup_info', 'Playgroup Programme', 'Ages: 1.5 - 2.5 Years | Duration: 2.5 Hours/Day', 'Our playgroup program focuses on laying a strong foundation by introducing basic language, math, and science concepts through engaging activities like art, music, dance, and play. We emphasize sensory exploration, gross motor development, and peer socialization in a safe, warm environment.', '["Sensory play and tactile exploration activities.", "Language and math concept introduction via music and stories.", "Development of gross and fine motor coordination milestones.", "Warm, secure environment designed to ease home-to-school transition."]', '/assets/images/program_toddler.jpg', 1, 2);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (13, 'preschool_program', 'nursery_info', 'Nursery Programme', 'Ages: 2.5 - 3.5 Years | Duration: 3 Hours/Day', 'Our nursery program encourages children to think, explore, and ask questions. Learning is facilitated through multiple interactive ''learning stations'' spread across the classroom, allowing kids to build their own learning path, develop pre-literacy, numeracy, and cooperative play habits.', '["Encouraging active questioning and independent inquiry.", "Learning stations for personalized choices and hands-on activities.", "Structured pre-reading, pre-writing, and phonics readiness.", "Developing cognitive, math reasoning, and creative expressions."]', '/assets/images/program_preschool.jpg', 1, 3);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (14, 'preschool_program', 'curriculum_pillars', 'The iCan Learning Pillars', 'Innovative, Agile, and Child-Centric Pedagogy', 'The iCan Learning System is a research-based pedagogical framework that connects developmental statements directly to neuroscience research, Bloom''s Taxonomy, and Howard Gardner''s Multiple Intelligences theory. We move past rote learning to inspire innovators and leaders.', '["9 Core Future Skills (collaboration, creativity, and problem-solving).", "15 Habits of Mind (persistence, independent thinking, and curiosity).", "STEAM theme-based experiential exploration projects.", "Integrated mathematics using the ELPS approach (Experience, Language, Picture, Symbol)."]', '/assets/images/curriculum_learning.png', 1, 4);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (15, 'about', 'about_intro', 'About Us', 'Who We Are', 'Vidyankuram Kids International Preschool is India''s premier early childhood education brand, dedicated to nurturing the unique potential within every child. Founded on the belief that the first five years of a child''s life are the most formative, we have built a learning ecosystem that is emotionally supportive, developmentally appropriate, and internationally benchmarked.
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (16, 'about', 'about_vision', 'Our Vision', 'What We Strive For', 'To spark human greatness in every single child — by discovering and then nurturing each child''s unique gift, so they may grow into confident, compassionate, and creative individuals who contribute meaningfully to the world.', NULL, '/assets/images/curriculum_learning.jpg', 1, 2);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (17, 'about', 'about_purpose', 'Our Purpose', 'Why We Exist', 'To create learning environments that accommodate all individual learners, providing them with opportunities to maximise their inherent potential. We believe that when children are given the freedom to learn, explore, and express in a nurturing setting, they flourish — academically, emotionally, and socially.', NULL, '/assets/images/admissions_banner.jpg', 1, 3);
INSERT INTO [page_sections] ([id], [page_code], [section_code], [title], [subtitle], [description], [content_json], [media_url], [is_active], [sort_order]) VALUES (18, 'about', 'about_philosophy', 'Our Philosophy', 'The Vidyankuram Kids Way', 'Our philosophy is rooted in the conviction that ''Every Child Can''. We move beyond rote learning to foster creativity, individuality, and independent thinking. We build on five foundational beliefs that guide every interaction, activity, and environment we create:', '[{"title": "Individual Creative Thoughts Over Passive Obedience", "desc": "We nurture innovators and thinkers rather than passive absorbers of information. Children are encouraged to question, create, and express their unique ideas."}, {"title": "Wisdom Over Knowledge", "desc": "We prioritise sound values, ethics, and the application of knowledge over mere memorisation. A wise child understands not just ''what'' but ''why'' and ''how''."}, {"title": "A United World Over a Divided One", "desc": "We help children understand that boundaries of race, religion, and region are superficial. Our classrooms celebrate diversity and foster empathy for all people."}, {"title": "Spirituality Over Religion", "desc": "We teach children that spirituality \u2014 the sense of wonder, gratitude, and inner strength \u2014 is the soul of all religions and a foundation for lifelong well-being."}, {"title": "Aspiration Over Ambition", "desc": "We encourage children to discover and build upon their own strengths and passions, rather than simply fulfilling the ambitions others have set for them."}]', NULL, 1, 4);
INSERT INTO [programs] ([id], [title], [age_group], [duration], [description], [highlights_json], [weekly_plan_json], [uniform_items_json], [image_url], [is_active], [sort_order]) VALUES (1, 'Toddler Explorers (Robo-Tots)', '1.5 - 2.5 Years', '2 Hours / Day', 'Start the journey of exploration! Toddlers develop sensory skills, fine motor coordination, and simple vocabulary by playing with soft tactile toys, colorful buttons, and friendly light-up robot helpers.', '["Sensory play activities","Basic social behavior","Language development","Parent-child bonding"]', '[{"day":"Monday","study":"Colorful Shapes Exploration","physical":"Robo-Crawl Obstacle Course","games":"Tactile Block Stacking","breakfast":"Apple Puree & Warm Milk--ddddddddddddd"},{"day":"Tuesday","study":"First Animal Sounds & Imitation","physical":"Tiny Jump & Dance Party","games":"Soft Ball Roller Chase","breakfast":"Oats Porridge & Banana Slices"},{"day":"Wednesday","study":"Robo-Alphabet Sounds (A-G)","physical":"Happy Toddler Yoga Stretch","games":"Glow Button Activity Puzzles","breakfast":"Sweet Potato Mash & Milk"},{"day":"Thursday","study":"Discovering Primary Colors","physical":"Bubble Catching Race","games":"Friendly Toy Sorting Match","breakfast":"Mashed Avocado & Berry Puree"},{"day":"Friday","study":"Interactive Storytelling Beats","physical":"Free Play Balloon Bounce","games":"Robo-Pet Hide & Seek","breakfast":"Rice Kheer (Nut-Free) & Milk"}]', '["Books","School Shorts","Vidyankuram Shoes","Bags"]', '/assets/images/program_toddler.jpg', 1, 1);
INSERT INTO [programs] ([id], [title], [age_group], [duration], [description], [highlights_json], [weekly_plan_json], [uniform_items_json], [image_url], [is_active], [sort_order]) VALUES (2, 'Preschool Engineers (Junior Coders)', '2.5 - 3.5 Years', '3 Hours / Day', 'Young minds begin structured play! Introduces phonics, writing prep, and basic logic sequencing. Kids learn to direct friendly rolling robots through colorful mazes, turning logic into a game.', '["Phonics introduction", "Pre-writing activities", "Simple counting games", "Art & Craft sessions"]', '[{"day": "Monday", "study": "Logical Order & Step Sequencing", "physical": "Agility Ladder Running", "games": "Rolling Robot Path Maze", "breakfast": "Whole Wheat Pancakes & Fruit Salad"}, {"day": "Tuesday", "study": "Phonics Sounds & Letter Writing", "physical": "Animal Crawls Workout", "games": "Block Coding Card Battles", "breakfast": "Scrambled Eggs & Mango Cubes"}, {"day": "Wednesday", "study": "Creative Counting & Pattern Sorting", "physical": "Fun Hula-Hoop Drills", "games": "Tiny Robot Obstacle Challenge", "breakfast": "Ragi Dosa & Apple Juice"}, {"day": "Thursday", "study": "Design Thinking Basics", "physical": "Relay Balloon Bounces", "games": "Engineering Bricks Sandbox", "breakfast": "Cornflakes with Banana & Milk"}, {"day": "Friday", "study": "Robo-Logic & Direction Commands", "physical": "Active Fun Dance Moves", "games": "Kids Coding Race Rally", "breakfast": "Vegetable Poha (No Peanuts) & Fruit Juice"}]', '["Books", "School Blazer", "School Shorts", "Pants", "Vidyankuram Shoes", "Girls Dress", "School Tie"]', '/assets/images/program_preschool.jpg', 1, 2);
INSERT INTO [programs] ([id], [title], [age_group], [duration], [description], [highlights_json], [weekly_plan_json], [uniform_items_json], [image_url], [is_active], [sort_order]) VALUES (3, 'Kindergarten Innovators (Future Designers)', '3.5 - 5.5 Years', '4 Hours / Day', 'Prepares children for school and beyond! Advanced reading, mathematics, scientific curiosity, and team challenges. Kids program block-based smart toys to solve creative classroom puzzles.', '["Advanced reading & spelling", "Basic mathematics & logic", "Environmental studies", "Show & Tell public speaking"]', '[{"day": "Monday", "study": "Block-based Code Functions", "physical": "Speed & Coordination Ladder", "games": "Programmed Robot Maze Solvers", "breakfast": "Veggie Sandwich & Berry Mix"}, {"day": "Tuesday", "study": "Scientific Observation Labs", "physical": "Junior Core Gym Stretch", "games": "Robo-Soccer Team Tournament", "breakfast": "Boiled Eggs & Whole Wheat Toast"}, {"day": "Wednesday", "study": "Math Foundations & Number Logic", "physical": "Tug-of-War Group Games", "games": "Interactive Tech Board Build", "breakfast": "Oats Idli with Coconut Chutney"}, {"day": "Thursday", "study": "Environmental Science & Eco-Bots", "physical": "Shuttle Running Relay", "games": "Block Engineering Craft Labs", "breakfast": "Cheese Toast & Fresh Apple Slices"}, {"day": "Friday", "study": "Logic Circuits & Simple Engineering", "physical": "Fun Field Obstacle Run", "games": "Future Innovator Coding Showdown", "breakfast": "Multi-grain Paratha & Yogurt Cup"}]', '["Books", "School Blazer", "Pants", "Vidyankuram Shoes", "Girls Dress", "School Tie"]', '/assets/images/program_kindergarten.jpg', 1, 3);
INSERT INTO [programs] ([id], [title], [age_group], [duration], [description], [highlights_json], [weekly_plan_json], [uniform_items_json], [image_url], [is_active], [sort_order]) VALUES (4, 'Day Care / After School Care', '2.0 - 8.0 Years', 'Flexible Hours', 'A safe, clean, and engaging home away from home with healthy snacks, nap time, homework assistance, and creative activities.', '["Safe nap environments", "Healthy hot meals", "Interactive storytelling", "Supervised playtime"]', NULL, NULL, '/assets/images/gallery_play.jpg', 1, 4);
