INSERT INTO [testimonials] ([id], [author_name], [author_role], [quote], [rating], [image_url], [is_active], [sort_order]) VALUES (1, 'Mrs. Shalini Mehta', 'Mother of Vivaan (Preschool)', 'Sending Vivaan to Vidyankuram Club was the best decision we made. Within months, we saw massive improvement in his speech and how he interacts with other children. The teachers are incredibly warm and patient.', 5, '/assets/images/parent_avatar1.jpg', 1, 1);
INSERT INTO [testimonials] ([id], [author_name], [author_role], [quote], [rating], [image_url], [is_active], [sort_order]) VALUES (2, 'Mr. Rajesh Iyer', 'Father of Aarav (Kindergarten)', 'The curriculum here is outstanding. It is not just about rote learning; they teach concepts through experiments, play, and stories. The security measures and daily updates give us absolute peace of mind.', 5, '/assets/images/parent_avatar2.jpg', 1, 2);
INSERT INTO [testimonials] ([id], [author_name], [author_role], [quote], [rating], [image_url], [is_active], [sort_order]) VALUES (3, 'Meera Sen', 'Mother of Kabir (Nursery)', 'Wonderful learning wiggles! My child loves the block building sessions.', 5, '/assets/images/parent_avatar1.jpg', 1, 3);
INSERT INTO [testimonials] ([id], [author_name], [author_role], [quote], [rating], [image_url], [is_active], [sort_order]) VALUES (4, 'David Craig', 'Father of Emily (Playgroup)', 'Very clean campus and excellent caretakers. Fully satisfied.', 4, '/assets/images/parent_avatar2.jpg', 1, 4);
INSERT INTO [testimonials] ([id], [author_name], [author_role], [quote], [rating], [image_url], [is_active], [sort_order]) VALUES (5, 'Rohan Kapur', 'Parent of Vivaan (KG)', 'Playground equipment needs a safety check, some swings are wobbly. Staff is responsive though.', 3, '', 0, 10);
INSERT INTO [testimonials] ([id], [author_name], [author_role], [quote], [rating], [image_url], [is_active], [sort_order]) VALUES (6, 'Tina Watson', 'Parent of Leo (Playgroup)', 'School bus route timings are delayed by 15 mins sometimes. Need better coordination.', 2, '', 0, 11);
